VALUES
  ('elementary-7c4986e7-moex-00050', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-862adcfa', 'sub-elementary-7c4986e7-01', NULL, 'single_choice', '要保人以其所有之藝術品、古玩品等無法依市價估定價值之物品要保者，依我國保險法第 73 條及第 75 條規定，係為：', '["足額保險", "古董保險", "定值保險", "不定額保險"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "469a90b16e7f", "answer_pdf_sha1": "2a8efabd8071", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "保險學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL),
  ('elementary-7c4986e7-moex-00051', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-b3f42868', 'sub-elementary-7c4986e7-02', NULL, 'single_choice', '我國憲法第23條規定：「以上各條列舉之自由權利，除為防止妨害他人自由、避免緊急危難、維持社會', '["比例原則", "法律保留原則", "誠實信用原則", "信賴保護原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:36+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL),
  ('elementary-7c4986e7-moex-00052', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-b3f42868', 'sub-elementary-7c4986e7-02', NULL, 'single_choice', '1989 年國小老師李幸長發起「無殼蝸牛運動」，夜宿臺北市忠孝東路，抗議政府漠視人民的居住權益。 後來，無住屋運動轉型為「崔媽媽基金會」，透過協助弱勢族群解決租屋問題，落實「居者適其屋」的 理念。關於「無殼蝸牛運動」發展到「崔媽媽基金會」之成立，下列敘述何者正確？', '["由非營利組織轉型為營利組織", "原強調利他主義後轉為主張利己導向", "原以公益為使命後轉為重視成本效益", "從倡議的社會運動轉為成立服務性的社團"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:36+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL),
  ('elementary-7c4986e7-moex-00053', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-b3f42868', 'sub-elementary-7c4986e7-02', NULL, 'single_choice', '近年來雙薪家庭比例上升，由於父母忙於工作，因此托兒所、安親班等機構成為安置孩童的重要處所。 根據統計，臺灣目前有政府立案的各種安親班、補習班、才藝班數量遠遠超過全臺超商數量。此現象說 明隨著社會變遷，家庭的何種功能正在轉變？', '["生育功能", "經濟功能", "社會化功能", "傳遞社會地位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:36+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL),
  ('elementary-7c4986e7-moex-00054', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-b3f42868', 'sub-elementary-7c4986e7-02', NULL, 'single_choice', '所謂「友善職場」，就是無歧視、重平等的職場。在職場中，勞工與雇主彼此尊重、合作，共同打造一 個性別平權的工作環境。下列何種作法，最有助於促進「友善職場」？', '["開放同志勞工因伴侶生病時可請家庭照顧假", "營造玻璃天花板環境以便落實性別實質平等", "健全性別職業隔離制度以保障女性就業機會", "降低女性勞動參與率以避免蠟燭兩頭燒現象"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:36+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL),
  ('elementary-7c4986e7-moex-00055', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-b3f42868', 'sub-elementary-7c4986e7-02', NULL, 'single_choice', '有關法律分類的敘述，下列何者正確？', '["民法：不成文法、私法、普通法、實體法", "民事訴訟法：成文法、私法、特別法、程序法", "刑事訴訟法：成文法、公法、普通法、程序法", "勞動基準法：不成文法、社會法、特別法、實體法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:36+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL),
  ('elementary-7c4986e7-moex-00056', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-b3f42868', 'sub-elementary-7c4986e7-02', NULL, 'single_choice', '隨著高齡化社會的來臨，國際移工的身影已深入臺灣家庭，然而媒體總以「口音怪異、膚色黝黑、吵雜 或是忠誠度不足、常常逃跑」來形容移工的樣貌。由此可知，媒體主要是透過下列何種方式來影響閱聽 人的認知？', '["總白癡化", "置入性行銷", "暴力行為的複製", "形塑刻板印象與歧視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:36+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL),
  ('elementary-7c4986e7-moex-00057', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-b3f42868', 'sub-elementary-7c4986e7-02', NULL, 'single_choice', '根據公民投票法之規定：「當國家遭受外力威脅，致國家主權有改變之虞，甲得經行政院院會之決議， 就攸關國家安全事項，交付公民投票。」關於甲的法定職權，下列敘述何者正確？', '["可向立法院提出覆議", "享有被動解散國會權", "可以提出憲法修正案", "掌理公務員懲戒事宜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:36+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL),
  ('elementary-7c4986e7-moex-00058', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-b3f42868', 'sub-elementary-7c4986e7-02', NULL, 'single_choice', '甲香雞排店位於社區中，炸雞排時排放的油煙與味道往往導致附近居民抗議，因此環保局對甲香雞排店 開罰並要求加裝符合環保標準的靜電油煙處理設備。若以香雞排價格為縱軸，香雞排數量為橫軸，針對 上述的分析說明，下列何者正確？', '["環保局對雞排店的開罰是屬於確立財產權的作法", "處罰與要求加裝過濾設備會導致市場供給線左移", "環保局可以對居民補貼來減少店家產生外部成本", "雞排店被勒令加裝環保設備即是體現了市場機能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:36+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL),
  ('elementary-7c4986e7-moex-00059', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-b3f42868', 'sub-elementary-7c4986e7-02', NULL, 'single_choice', '我國現行的立法委員選舉，其選舉制度如下：區域立委選舉採（甲）選舉制度，原住民立委選舉採（乙） 選舉制度，全國不分區立委選舉採（丙）選舉制度，下列敘述何者正確？', '["（甲）（乙）選舉制度皆有利於大黨", "（丙）以區域候選人所得票數比例換算政黨席位", "（乙）（丙）皆有婦女保障名額的限制", "（甲）為一個選區只有一人當選的選制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:36+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL)
